"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export const DATA_PANEL_CARD_CLASS_NAME = "overflow-hidden rounded-[1.35rem] border border-border/70 bg-card/95 shadow-[0_1px_0_rgba(255,255,255,0.65),0_18px_48px_-32px_rgba(15,23,42,0.28)]"
export const DATA_PANEL_HEADER_CLASS_NAME = "border-b border-border/60 bg-[linear-gradient(180deg,color-mix(in_srgb,var(--background)_84%,var(--muted))_0%,color-mix(in_srgb,var(--background)_96%,transparent)_100%)] px-5 py-4 md:px-6"
export const DATA_PANEL_CONTENT_CLASS_NAME = "px-5 py-5 md:px-6 md:py-6"
export const DATA_PANEL_SECTION_CLASS_NAME = "rounded-[1.1rem] border border-border/60 bg-muted/[0.16] shadow-[inset_0_1px_0_rgba(255,255,255,0.4)]"
export const DATA_TOOLBAR_CARD_CLASS_NAME = "rounded-[1.25rem] border border-border/70 bg-card/90 px-4 py-4 shadow-[0_1px_0_rgba(255,255,255,0.55),0_16px_38px_-34px_rgba(15,23,42,0.35)]"
export const DATA_TABLE_FRAME_CLASS_NAME = "overflow-hidden rounded-[1.25rem] border border-border/70 bg-background/95 shadow-[0_1px_0_rgba(255,255,255,0.52),0_20px_45px_-40px_rgba(15,23,42,0.4)]"
export const DATA_FLOATING_BAR_CLASS_NAME = "rounded-full border border-border/70 bg-background/85 px-5 py-2.5 shadow-[0_18px_50px_-28px_rgba(15,23,42,0.45)] backdrop-blur-md supports-[backdrop-filter]:bg-background/78"
export const DATA_INPUT_CLASS_NAME = "rounded-xl border border-border/70 bg-background/90 shadow-[0_1px_0_rgba(255,255,255,0.45)] transition-colors hover:border-border focus-visible:border-ring"
export const DATA_SUBTLE_ACTION_CLASS_NAME = "rounded-xl border border-border/60 bg-background/80 text-muted-foreground transition-colors hover:border-border hover:bg-muted/40 hover:text-foreground"
export const DATA_DIVIDER_CLASS_NAME = "bg-border/60"
export const DATA_RUNNER_CARD_CLASS_NAME = "overflow-hidden rounded-[1.25rem] border border-border/70 bg-card/95 shadow-[0_1px_0_rgba(255,255,255,0.55),0_14px_36px_-32px_rgba(15,23,42,0.22)]"
export const DATA_LIST_ITEM_CLASS_NAME = "rounded-[1rem] border border-border/60 bg-muted/[0.16] px-4 py-3 shadow-[inset_0_1px_0_rgba(255,255,255,0.4)] transition-colors hover:bg-muted/[0.26]"
export const DATA_STATUS_BOX_CLASS_NAME = "rounded-[1rem] border border-border/60 bg-muted/[0.16] px-4 py-3.5 shadow-[inset_0_1px_0_rgba(255,255,255,0.4)]"
export const DATA_CODE_BLOCK_CLASS_NAME = "max-h-[360px] overflow-auto rounded-[1rem] border border-border/60 bg-muted/[0.16] p-4 text-sm leading-6 shadow-[inset_0_1px_0_rgba(255,255,255,0.4)]"
export const DATA_FIELD_LABEL_CLASS_NAME = "text-[11px] font-semibold uppercase tracking-[0.14em] text-muted-foreground"
export const DATA_TYPE_BADGE_CLASS_NAME = "rounded-full border px-2.5 py-1 text-[10px] font-medium uppercase tracking-[0.14em]"

type DataStateTone = "neutral" | "danger" | "success"

export function dataWorkspaceStateClassName(tone: DataStateTone = "neutral"): string {
  if (tone === "danger") {
    return "rounded-[1rem] border border-destructive/25 bg-destructive/10 px-4 py-4 text-sm text-destructive shadow-[inset_0_1px_0_rgba(255,255,255,0.3)]"
  }

  if (tone === "success") {
    return "rounded-[1rem] border border-emerald-500/20 bg-emerald-500/10 px-4 py-4 text-sm text-emerald-700 shadow-[inset_0_1px_0_rgba(255,255,255,0.3)] dark:text-emerald-300"
  }

  return "rounded-[1rem] border border-dashed border-border/70 bg-muted/[0.2] px-4 py-6 text-sm text-muted-foreground shadow-[inset_0_1px_0_rgba(255,255,255,0.3)]"
}

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-border/50 transition-colors duration-150",
    options?.interactive && "cursor-pointer hover:bg-muted/[0.26]",
    options?.selected && "bg-foreground/[0.05] hover:bg-foreground/[0.07]",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between", className)}>
      <div className="min-w-0 space-y-3">
        <div className="space-y-1.5">
          {eyebrow ? (
            <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-muted-foreground/90">
              {eyebrow}
            </div>
          ) : null}
          <div className="text-lg font-semibold leading-tight tracking-[-0.01em] text-foreground md:text-xl">
            {title}
          </div>
          {description ? (
            <div className="max-w-3xl text-sm leading-6 text-muted-foreground">
              {description}
            </div>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div className={cn(dataWorkspaceStateClassName(tone), className)} {...props}>
      <div className="grid gap-1.5">
        {heading ? (
          <div className="text-sm font-medium text-foreground">
            {heading}
          </div>
        ) : null}
        <div className={cn("leading-6", tone === "neutral" ? "text-muted-foreground" : undefined)}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecords, useTable } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { cn } from "@/lib/utils"
import {
  DATA_PANEL_CARD_CLASS_NAME,
  DATA_PANEL_CONTENT_CLASS_NAME,
  DATA_PANEL_HEADER_CLASS_NAME,
  DATA_SUBTLE_ACTION_CLASS_NAME,
  DATA_TABLE_FRAME_CLASS_NAME,
  DataWorkspaceHeader,
  DataWorkspaceState,
  dataWorkspaceMetaBadgeClassName,
  dataWorkspaceRowClassName,
  dataWorkspaceTypeBadgeClassName,
} from "@/components/lemma/registry-data-workspace"

type LemmaRecordsTableButtonVariant =
  | "default"
  | "outline"
  | "secondary"
  | "ghost"
  | "destructive"
  | "link"

export interface LemmaRecordsTableColumn {
  name: string
  label?: string
  description?: string
  type?: string
  width?: number | string
  minWidth?: number | string
  align?: "start" | "center" | "end"
  searchable?: boolean
  hideable?: boolean
  hidden?: boolean
  headerClassName?: string
  cellClassName?: string
  renderCell?: (args: {
    record: Record<string, unknown>
    value: unknown
    column: LemmaRecordsTableColumn
    rowIndex: number
    isSelected: boolean
  }) => React.ReactNode
}

export interface LemmaRecordsTableRowAction {
  key: string
  label: string
  onClick: (record: Record<string, unknown>) => void
  disabled?: (record: Record<string, unknown>) => boolean
  variant?: LemmaRecordsTableButtonVariant
}

export interface LemmaRecordsTableProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  tableName: string
  title?: string
  description?: string
  limit?: number
  records?: Record<string, unknown>[]
  isLoading?: boolean
  error?: Error | null
  onRefresh?: () => void
  columnNames?: string[]
  columns?: LemmaRecordsTableColumn[]
  maxColumns?: number
  search?: string
  searchFields?: string[]
  selectedRecordId?: string | null
  recordIdField?: string
  getRecordId?: (record: Record<string, unknown>) => string
  emptyText?: string
  onRowSelect?: (record: Record<string, unknown>) => void
  showSelection?: boolean
  selectedRecordIds?: string[]
  onSelectedRecordIdsChange?: (recordIds: string[]) => void
  pageIndex?: number
  pageSize?: number
  totalCount?: number
  hasNextPage?: boolean
  onPreviousPage?: () => void
  onNextPage?: () => void
  density?: "compact" | "comfortable"
  hiddenColumnNames?: string[]
  defaultHiddenColumnNames?: string[]
  onHiddenColumnNamesChange?: (hiddenColumnNames: string[]) => void
  allowColumnVisibility?: boolean
  columnVisibilityLabel?: string
  onCreateRecord?: () => void
  createButtonLabel?: string
  rowActions?: LemmaRecordsTableRowAction[]
  rowActionsLabel?: string
  onError?: (error: Error) => void
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function readRecordId(
  record: Record<string, unknown>,
  recordIdField: string,
  getRecordId?: (record: Record<string, unknown>) => string,
): string {
  if (getRecordId) {
    const customId = getRecordId(record)
    return typeof customId === "string" ? customId : ""
  }

  const value = record[recordIdField]
  if (typeof value === "string") return value
  if (typeof value === "number") return String(value)
  return ""
}

function sentenceCase(value: string): string {
  return value
    .replace(/[_\.]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function normalizeWidth(value?: number | string): string | undefined {
  if (typeof value === "number") return `${value}px`
  return value
}

function alignClassName(align: LemmaRecordsTableColumn["align"]): string {
  if (align === "center") return "text-center"
  if (align === "end") return "text-right"
  return "text-left"
}

function headerLabel(column: LemmaRecordsTableColumn): string {
  return column.label ?? column.name
}

function renderCellValue(value: unknown, column: LemmaRecordsTableColumn): React.ReactNode {
  const normalizedType = (column.type ?? "text").toLowerCase()

  if (value === null || typeof value === "undefined" || value === "") {
    return <span className="text-muted-foreground">—</span>
  }

  if ((normalizedType === "enum" || normalizedType === "select") && typeof value === "string") {
    return (
      <Badge
        className={cn("rounded-full border px-2.5 py-1 text-xs font-medium uppercase tracking-[0.14em]", dataWorkspaceMetaBadgeClassName("primary"))}
        variant="outline"
      >
        {value}
      </Badge>
    )
  }

  return formatValue(value)
}

export const LemmaRecordsTable = React.forwardRef<HTMLDivElement, LemmaRecordsTableProps>(
  ({
    client,
    podId,
    tableName,
    title,
    description,
    limit = 10,
    records,
    isLoading,
    error,
    onRefresh,
    columnNames,
    columns,
    maxColumns = 6,
    search,
    searchFields,
    selectedRecordId,
    recordIdField = "id",
    getRecordId,
    emptyText = "No records found for this table.",
    onRowSelect,
    showSelection = false,
    selectedRecordIds,
    onSelectedRecordIdsChange,
    pageIndex = 0,
    pageSize = limit,
    totalCount,
    hasNextPage = false,
    onPreviousPage,
    onNextPage,
    density = "comfortable",
    hiddenColumnNames,
    defaultHiddenColumnNames = [],
    onHiddenColumnNamesChange,
    allowColumnVisibility = false,
    columnVisibilityLabel = "Columns",
    onCreateRecord,
    createButtonLabel = "New Record",
    rowActions = [],
    rowActionsLabel = "Actions",
    onError,
    className,
    ...props
  }, ref) => {
    const trimmedTableName = tableName.trim()
    const tableState = useTable({
      client,
      podId,
      tableName: trimmedTableName,
      enabled: trimmedTableName.length > 0,
    })
    const recordsState = useRecords({
      client,
      podId,
      tableName: trimmedTableName,
      enabled: trimmedTableName.length > 0 && !records,
      limit,
    })
    const effectiveRecords = records ?? recordsState.records
    const effectiveIsLoading = isLoading ?? recordsState.isLoading
    const effectiveError = error ?? recordsState.error

    React.useEffect(() => {
      if (effectiveError) {
        onError?.(effectiveError)
      }
    }, [effectiveError, onError])

    const deferredSearch = React.useDeferredValue(search ?? "")
    const [isColumnEditorOpen, setIsColumnEditorOpen] = React.useState(false)
    const [internalHiddenColumnNames, setInternalHiddenColumnNames] = React.useState(defaultHiddenColumnNames)

    const setResolvedHiddenColumnNames = React.useCallback((nextHiddenColumnNames: string[]) => {
      if (typeof hiddenColumnNames === "undefined") {
        setInternalHiddenColumnNames(nextHiddenColumnNames)
      }
      onHiddenColumnNamesChange?.(nextHiddenColumnNames)
    }, [hiddenColumnNames, onHiddenColumnNamesChange])

    const resolvedHiddenColumnNames = hiddenColumnNames ?? internalHiddenColumnNames

    const allColumns = React.useMemo<LemmaRecordsTableColumn[]>(() => {
      if (columns?.length) {
        return columns
      }

      if (columnNames?.length) {
        return columnNames.map((columnName) => {
          const schemaColumn = tableState.table?.columns.find((column) => column.name === columnName)
          return {
            name: columnName,
            label: columnName,
            type: schemaColumn?.type?.toLowerCase() ?? "text",
          } satisfies LemmaRecordsTableColumn
        })
      }

      const schemaColumns = tableState.table?.columns
        .filter((column) => column.name !== "created_at" && column.name !== "updated_at")
        .slice(0, maxColumns)
        .map((column) => ({
          name: column.name,
          label: column.name,
          type: column.type.toLowerCase(),
        } satisfies LemmaRecordsTableColumn))

      if (schemaColumns && schemaColumns.length > 0) {
        return schemaColumns
      }

      const discoveredKeys = Array.from(
        new Set(effectiveRecords.flatMap((record) => Object.keys(record))),
      ).slice(0, maxColumns)

      return discoveredKeys.map((columnName) => ({
        name: columnName,
        label: columnName,
        type: "text",
      } satisfies LemmaRecordsTableColumn))
    }, [columnNames, columns, effectiveRecords, maxColumns, tableState.table])

    const hiddenColumnNameSet = React.useMemo(() => {
      const names = new Set(resolvedHiddenColumnNames)
      allColumns.forEach((column) => {
        if (column.hidden) {
          names.add(column.name)
        }
      })
      return names
    }, [allColumns, resolvedHiddenColumnNames])

    const visibleColumns = React.useMemo(
      () => allColumns.filter((column) => !hiddenColumnNameSet.has(column.name)),
      [allColumns, hiddenColumnNameSet],
    )

    const searchableFieldNames = React.useMemo(() => {
      if (searchFields?.length) return searchFields
      return allColumns
        .filter((column) => column.searchable !== false)
        .map((column) => column.name)
    }, [allColumns, searchFields])

    const filteredRecords = React.useMemo(() => {
      const normalizedSearch = deferredSearch.trim().toLowerCase()
      if (!normalizedSearch) return effectiveRecords

      return effectiveRecords.filter((record) => searchableFieldNames.some((field) => {
        const value = record[field]
        if (typeof value === "string") return value.toLowerCase().includes(normalizedSearch)
        if (typeof value === "number" || typeof value === "boolean") {
          return String(value).toLowerCase().includes(normalizedSearch)
        }
        return false
      }))
    }, [deferredSearch, effectiveRecords, searchableFieldNames])

    const selectedIdSet = React.useMemo(
      () => new Set(selectedRecordIds ?? []),
      [selectedRecordIds],
    )
    const visibleSelectableIds = React.useMemo(
      () => filteredRecords
        .map((record) => readRecordId(record, recordIdField, getRecordId))
        .filter((value) => value.length > 0),
      [filteredRecords, getRecordId, recordIdField],
    )
    const allVisibleSelected = visibleSelectableIds.length > 0
      && visibleSelectableIds.every((recordId) => selectedIdSet.has(recordId))
    const selectionEnabled = showSelection && !!onSelectedRecordIdsChange
    const resolvedTotalCount = typeof totalCount === "number" ? totalCount : filteredRecords.length
    const rangeStart = resolvedTotalCount === 0 ? 0 : (pageIndex * pageSize) + 1
    const rangeEnd = Math.min((pageIndex * pageSize) + filteredRecords.length, resolvedTotalCount)
    const rowPadding = density === "compact" ? "py-3" : "py-4"
    const hasRowActions = rowActions.length > 0

    const toggleRecordSelection = React.useCallback((recordId: string, checked: boolean) => {
      if (!onSelectedRecordIdsChange) return

      const nextSelection = new Set(selectedRecordIds ?? [])
      if (checked) {
        nextSelection.add(recordId)
      } else {
        nextSelection.delete(recordId)
      }
      onSelectedRecordIdsChange(Array.from(nextSelection))
    }, [onSelectedRecordIdsChange, selectedRecordIds])

    const toggleVisibleSelection = React.useCallback((checked: boolean) => {
      if (!onSelectedRecordIdsChange) return

      const nextSelection = new Set(selectedRecordIds ?? [])
      visibleSelectableIds.forEach((recordId) => {
        if (checked) {
          nextSelection.add(recordId)
        } else {
          nextSelection.delete(recordId)
        }
      })
      onSelectedRecordIdsChange(Array.from(nextSelection))
    }, [onSelectedRecordIdsChange, selectedRecordIds, visibleSelectableIds])

    if (!trimmedTableName) {
      return (
        <Card ref={ref} className={cn(DATA_PANEL_CARD_CLASS_NAME, className)} {...props}>
          <CardHeader className={DATA_PANEL_HEADER_CLASS_NAME}>
            <CardTitle>{title ?? "Records Table"}</CardTitle>
            <CardDescription>{description ?? "Select a table to preview its records."}</CardDescription>
          </CardHeader>
        </Card>
      )
    }

    return (
      <div ref={ref} className={cn("", className)} {...props}>
        <div className="grid gap-4">
          {(title || description || onCreateRecord || allowColumnVisibility || onRefresh) ? (
            <div className={cn("rounded-[1.25rem] border border-border/70 bg-card/90 p-5 shadow-[0_1px_0_rgba(255,255,255,0.48),0_16px_42px_-34px_rgba(15,23,42,0.35)]", DATA_PANEL_HEADER_CLASS_NAME)}>
              <DataWorkspaceHeader
                actions={(
                  <>
                    {allowColumnVisibility && allColumns.length > 0 ? (
                      <Button
                        className={DATA_SUBTLE_ACTION_CLASS_NAME}
                        onClick={() => setIsColumnEditorOpen(true)}
                        type="button"
                        variant="ghost"
                      >
                        {columnVisibilityLabel}
                      </Button>
                    ) : null}
                    <Button
                      className={DATA_SUBTLE_ACTION_CLASS_NAME}
                      disabled={effectiveIsLoading}
                      onClick={() => {
                        if (onRefresh) {
                          onRefresh()
                          return
                        }
                        void recordsState.refresh()
                      }}
                      type="button"
                      variant="ghost"
                    >
                      {effectiveIsLoading ? "Refreshing..." : "Refresh"}
                    </Button>
                    {onCreateRecord ? (
                      <Button onClick={onCreateRecord} type="button">
                        {createButtonLabel}
                      </Button>
                    ) : null}
                  </>
                )}
                description={description ?? `Preview the latest ${limit} records from this table.`}
                eyebrow="Records"
                meta={(
                  <>
                    <Badge className={cn("rounded-full border px-2.5 py-1 text-[11px] font-medium uppercase tracking-[0.14em]", dataWorkspaceMetaBadgeClassName("primary"))} variant="outline">
                      {trimmedTableName}
                    </Badge>
                    <Badge className={cn("rounded-full border px-2.5 py-1 text-[11px] font-medium uppercase tracking-[0.14em]", dataWorkspaceMetaBadgeClassName("default"))} variant="outline">
                      {filteredRecords.length} row{filteredRecords.length === 1 ? "" : "s"}
                    </Badge>
                    <Badge className={cn("rounded-full border px-2.5 py-1 text-[11px] font-medium uppercase tracking-[0.14em]", dataWorkspaceMetaBadgeClassName("default"))} variant="outline">
                      {visibleColumns.length} column{visibleColumns.length === 1 ? "" : "s"}
                    </Badge>
                  </>
                )}
                title={title ?? `Records: ${trimmedTableName}`}
              />
            </div>
          ) : null}

          <div className={DATA_TABLE_FRAME_CLASS_NAME}>
            {effectiveError ? (
              <DataWorkspaceState className="m-4" description={effectiveError.message} tone="danger" />
            ) : null}

            {effectiveIsLoading && filteredRecords.length === 0 ? (
              <DataWorkspaceState className="m-4" description="Loading records..." heading="Fetching rows" />
            ) : null}

            {!effectiveIsLoading && filteredRecords.length === 0 ? (
              <DataWorkspaceState className="m-4" description={emptyText} heading="No rows found" />
            ) : null}

            {!effectiveIsLoading && filteredRecords.length > 0 && visibleColumns.length === 0 ? (
              <DataWorkspaceState className="m-4" description="All columns are currently hidden. Reopen the column picker to show fields." heading="Nothing visible" />
            ) : null}

            {filteredRecords.length > 0 && visibleColumns.length > 0 ? (
              <div className="overflow-hidden">
                <Table>
                  <TableHeader className="bg-muted/[0.28]">
                    <TableRow className="hover:bg-transparent">
                      {selectionEnabled ? (
                        <TableHead className="w-12 border-b border-border/60 px-3">
                          <Checkbox
                            aria-label="Select visible records"
                            checked={allVisibleSelected}
                            onCheckedChange={(checked) => toggleVisibleSelection(checked === true)}
                          />
                        </TableHead>
                      ) : null}
                      {visibleColumns.map((column) => (
                        <TableHead
                          className={cn(
                            "border-b border-border/60 px-4 py-3 align-middle",
                            alignClassName(column.align),
                            column.headerClassName,
                          )}
                          key={column.name}
                          style={{
                            minWidth: normalizeWidth(column.minWidth),
                            width: normalizeWidth(column.width),
                          }}
                        >
                          <div className="flex items-center gap-3">
                            <span className="text-[0.95rem] font-medium text-foreground/85">
                              {headerLabel(column)}
                            </span>
                            <Badge
                              className={cn(
                                "rounded-full border px-2.5 py-1 text-[10px] font-medium uppercase tracking-[0.14em]",
                                dataWorkspaceTypeBadgeClassName(column.type),
                              )}
                              variant="outline"
                            >
                              {column.type ?? "text"}
                            </Badge>
                          </div>
                        </TableHead>
                      ))}
                      {hasRowActions ? (
                        <TableHead className="border-b border-border/60 px-4 py-3 text-right text-foreground/80">
                          {rowActionsLabel}
                        </TableHead>
                      ) : null}
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {filteredRecords.map((record, index) => {
                      const rowId = readRecordId(record, recordIdField, getRecordId)
                      const isSelected = !!selectedRecordId && rowId === selectedRecordId

                      return (
                        <TableRow
                          className={cn(
                            dataWorkspaceRowClassName({
                              interactive: !!onRowSelect,
                              selected: isSelected,
                            }),
                            "align-top",
                          )}
                          key={rowId || index}
                          onClick={onRowSelect ? () => onRowSelect(record) : undefined}
                        >
                          {selectionEnabled ? (
                            <TableCell className={cn("w-12 px-3", rowPadding)}>
                              <Checkbox
                                aria-label={`Select record ${rowId || index + 1}`}
                                checked={selectedIdSet.has(rowId)}
                                onCheckedChange={(checked) => {
                                  if (!rowId) return
                                  toggleRecordSelection(rowId, checked === true)
                                }}
                                onClick={(event) => event.stopPropagation()}
                              />
                            </TableCell>
                          ) : null}
                          {visibleColumns.map((column) => {
                            const value = record[column.name]
                            const renderedValue = column.renderCell
                              ? column.renderCell({
                                  record,
                                  value,
                                  column,
                                  rowIndex: index,
                                  isSelected,
                                })
                              : renderCellValue(value, column)

                            return (
                              <TableCell
                                className={cn(
                                  "max-w-[360px] px-4 align-middle",
                                  rowPadding,
                                  alignClassName(column.align),
                                  column.cellClassName,
                                )}
                                key={column.name}
                                style={{
                                  minWidth: normalizeWidth(column.minWidth),
                                  width: normalizeWidth(column.width),
                                }}
                              >
                                <div
                                  className={cn(
                                    "text-[0.98rem] leading-7 text-foreground/92",
                                    typeof renderedValue === "string" || typeof renderedValue === "number" || typeof renderedValue === "boolean"
                                      ? "truncate"
                                      : "whitespace-normal",
                                  )}
                                  title={formatValue(value)}
                                >
                                  {renderedValue}
                                </div>
                              </TableCell>
                            )
                          })}
                          {hasRowActions ? (
                            <TableCell className={cn("px-4 text-right", rowPadding)}>
                              <div className="flex items-center justify-end gap-2">
                                {rowActions.map((action) => (
                                  <Button
                                    className={action.variant === "destructive" ? "" : DATA_SUBTLE_ACTION_CLASS_NAME}
                                    disabled={action.disabled?.(record) ?? false}
                                    key={action.key}
                                    onClick={(event) => {
                                      event.stopPropagation()
                                      action.onClick(record)
                                    }}
                                    size="sm"
                                    type="button"
                                    variant={action.variant ?? "ghost"}
                                  >
                                    {action.label}
                                  </Button>
                                ))}
                              </div>
                            </TableCell>
                          ) : null}
                        </TableRow>
                      )
                    })}
                  </TableBody>
                </Table>
              </div>
            ) : null}

            {resolvedTotalCount > 0 && (onPreviousPage || onNextPage) ? (
              <div className="flex flex-col gap-4 border-t border-border/60 bg-muted/[0.18] px-5 py-4 text-sm text-muted-foreground md:flex-row md:items-center md:justify-between">
                <div className="inline-flex items-center gap-2">
                  Showing {rangeStart}-{rangeEnd} of {resolvedTotalCount}
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    className={DATA_SUBTLE_ACTION_CLASS_NAME}
                    disabled={pageIndex === 0}
                    onClick={onPreviousPage}
                    type="button"
                    variant="ghost"
                  >
                    Previous
                  </Button>
                  <div className="text-sm text-muted-foreground">Page {pageIndex + 1}</div>
                  <Button
                    className={DATA_SUBTLE_ACTION_CLASS_NAME}
                    disabled={!hasNextPage}
                    onClick={onNextPage}
                    type="button"
                    variant="ghost"
                  >
                    Next
                  </Button>
                </div>
              </div>
            ) : null}
          </div>
        </div>

        <Sheet open={isColumnEditorOpen} onOpenChange={setIsColumnEditorOpen}>
          <SheetContent className="flex w-full flex-col gap-0 border-l border-border/60 bg-background/95 p-0 sm:max-w-xl" side="right">
            <SheetHeader className="border-b border-border/60 px-6 py-5 text-left">
              <SheetTitle>Choose Columns</SheetTitle>
              <SheetDescription>Show or hide fields for this table view.</SheetDescription>
            </SheetHeader>
            <div className="flex-1 overflow-y-auto px-6 py-6">
              <div className="grid gap-3">
                {allColumns.map((column) => {
                  const isHideable = column.hideable !== false
                  const isChecked = !hiddenColumnNameSet.has(column.name)

                  return (
                    <label
                      className={cn(
                        "grid gap-3 rounded-[1rem] border px-4 py-4 shadow-[inset_0_1px_0_rgba(255,255,255,0.35)]",
                        isHideable ? "cursor-pointer border-border/70 bg-background/95 hover:border-border hover:bg-muted/[0.18]" : "border-border/50 bg-muted/[0.22] opacity-70",
                      )}
                      key={column.name}
                    >
                      <div className="flex items-start gap-3">
                        <Checkbox
                          checked={isChecked}
                          disabled={!isHideable}
                          onCheckedChange={(checked) => {
                            if (!isHideable) return

                            const nextHiddenColumns = new Set(hiddenColumnNameSet)
                            if (checked === true) {
                              nextHiddenColumns.delete(column.name)
                            } else {
                              nextHiddenColumns.add(column.name)
                            }
                            setResolvedHiddenColumnNames(Array.from(nextHiddenColumns))
                          }}
                        />
                        <div className="grid gap-1.5">
                          <div className="flex flex-wrap items-center gap-2">
                            <span className="text-sm font-medium text-foreground">
                              {headerLabel(column)}
                            </span>
                            <Badge
                              className={cn(
                                "rounded-full border px-2.5 py-1 text-[10px] font-medium uppercase tracking-[0.14em]",
                                dataWorkspaceTypeBadgeClassName(column.type),
                              )}
                              variant="outline"
                            >
                              {column.type ?? "text"}
                            </Badge>
                          </div>
                          {column.description ? (
                            <p className="text-sm leading-6 text-muted-foreground">{column.description}</p>
                          ) : null}
                          {!isHideable ? (
                            <p className="text-xs text-muted-foreground">
                              This column is locked and cannot be hidden.
                            </p>
                          ) : null}
                        </div>
                      </div>
                    </label>
                  )
                })}
              </div>
            </div>
            <div className="border-t border-border px-6 py-5">
              <div className="flex items-center justify-end gap-3">
                <Button
                  className={DATA_SUBTLE_ACTION_CLASS_NAME}
                  onClick={() => setResolvedHiddenColumnNames([])}
                  type="button"
                  variant="ghost"
                >
                  Show All
                </Button>
                <Button className="rounded-xl" onClick={() => setIsColumnEditorOpen(false)} type="button">
                  Done
                </Button>
              </div>
            </div>
          </SheetContent>
        </Sheet>
      </div>
    )
  },
)
LemmaRecordsTable.displayName = "LemmaRecordsTable"
